import React, { useState } from 'react';
import {
  Container,
  Box,
  Typography,
  Button,
  Card,
  CardContent,
  CardMedia,
  Grid,
  Chip,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  ListItemAvatar,
  Switch,
  styled
} from '@mui/material';
import {
  Person as PersonIcon,
  Email as EmailIcon,
  Notifications as NotificationsIcon,
  Language as LanguageIcon,
  CreditCard as PaymentIcon,
  HeadsetMic as SupportIcon,
  Info as InfoIcon,
  Help as HelpIcon,
  Gavel as LegalIcon,
  Security as SecurityIcon,
  HelpOutline as HelpOutlineIcon
} from '@mui/icons-material';
import { useAuth } from '../context/AuthContext';

const MenuButton = styled(Button)({
  justifyContent: 'flex-start',
  textTransform: 'none',
  width: '100%',
  padding: '12px 16px',
  borderRadius: '8px',
  color: '#0C1F26',
  '&:hover': {
    backgroundColor: 'rgba(0, 128, 128, 0.05)',
  },
  '&.Mui-selected': {
    backgroundColor: 'rgba(0, 128, 128, 0.1)',
    color: '#008080',
    fontWeight: 600,
  },
  '&.Mui-selected:hover': {
    backgroundColor: 'rgba(0, 128, 128, 0.1)',
  },
});

const Profile = () => {
  const { user, logout } = useAuth();
  const [activeTab, setActiveTab] = useState('profile');
  const [notifications, setNotifications] = useState(true);
  const [emailNotifications, setEmailNotifications] = useState(true);

  const menuItems = [
    { id: 'profile', label: 'Personal Information', icon: <PersonIcon /> },
    { id: 'notifications', label: 'Notifications', icon: <NotificationsIcon /> },
    { id: 'payment', label: 'Payment Methods', icon: <PaymentIcon /> },
    { id: 'language', label: 'Language', icon: <LanguageIcon /> },
    { id: 'help', label: 'Help & Support', icon: <HelpIcon /> },
    { id: 'about', label: 'About', icon: <InfoIcon /> },
    { id: 'legal', label: 'Legal', icon: <LegalIcon /> },
    { id: 'security', label: 'Security', icon: <SecurityIcon /> },
  ];

  const renderContent = () => {
    switch (activeTab) {
      case 'profile':
        return (
          <Box>
            <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
              Personal Information
            </Typography>
            <Typography variant="body1" sx={{ mb: 2 }}>
              <strong>Name:</strong> {user.name}
            </Typography>
            <Typography variant="body1" sx={{ mb: 2 }}>
              <strong>Email:</strong> {user.email}
            </Typography>
            <Button 
              variant="outlined" 
              onClick={logout}
              sx={{ 
                mt: 2,
                color: '#008080',
                borderColor: '#008080',
                borderRadius: '9999px',
                fontWeight: 600,
                textTransform: 'none',
                '&:hover': {
                  borderColor: '#006666',
                  backgroundColor: 'rgba(0, 128, 128, 0.05)'
                }
              }}
            >
              Logout
            </Button>
          </Box>
        );
      case 'notifications':
        return (
          <Box>
            <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
              Notifications
            </Typography>
            <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
              <Box>
                <Typography variant="body1">Push Notifications</Typography>
                <Typography variant="body2" color="text.secondary">
                  For all your bookings and messages
                </Typography>
              </Box>
              <Switch 
                checked={notifications} 
                onChange={(e) => setNotifications(e.target.checked)} 
              />
            </Box>
            <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
              <Box>
                <Typography variant="body1">Email Notifications</Typography>
                <Typography variant="body2" color="text.secondary">
                  For important account notifications
                </Typography>
              </Box>
              <Switch 
                checked={emailNotifications} 
                onChange={(e) => setEmailNotifications(e.target.checked)} 
              />
            </Box>
          </Box>
        );
      case 'payment':
        return (
          <Box>
            <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
              Payment Methods
            </Typography>
            <Typography variant="body1">
              You haven't added any payment methods yet.
            </Typography>
            <Button 
              variant="outlined" 
              sx={{ 
                mt: 2,
                color: '#008080',
                borderColor: '#008080',
                borderRadius: '9999px',
                fontWeight: 600,
                textTransform: 'none',
                '&:hover': {
                  borderColor: '#006666',
                  backgroundColor: 'rgba(0, 128, 128, 0.05)'
                }
              }}
            >
              Add Payment Method
            </Button>
          </Box>
        );
      case 'language':
        return (
          <Box>
            <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
              Language
            </Typography>
            <Typography variant="body1">
              Current language: English
            </Typography>
          </Box>
        );
      case 'help':
        return (
          <Box>
            <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
              Help & Support
            </Typography>
            <List>
              <ListItem button>
                <ListItemIcon>
                  <HelpOutlineIcon />
                </ListItemIcon>
                <ListItemText primary="Help Center" />
              </ListItem>
              <ListItem button>
                <ListItemIcon>
                  <SupportIcon />
                </ListItemIcon>
                <ListItemText primary="Contact Support" />
              </ListItem>
            </List>
          </Box>
        );
      case 'about':
        return (
          <Box>
            <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
              <Box>
                <Typography variant="h4">RenThing</Typography>
                <Typography variant="subtitle1">Version 1.0.0</Typography>
              </Box>
            </Box>
            <Typography variant="body1">
              RenThing is a peer-to-peer rental marketplace that connects people who want to rent out their items with people who are looking to borrow.
            </Typography>
          </Box>
        );
      case 'legal':
        return (
          <Box>
            <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
              Legal
            </Typography>
            <List>
              <ListItem button>
                <ListItemIcon>
                  <InfoIcon />
                </ListItemIcon>
                <ListItemText primary="Terms of Service" />
              </ListItem>
              <ListItem button>
                <ListItemIcon>
                  <SecurityIcon />
                </ListItemIcon>
                <ListItemText primary="Privacy Policy" />
              </ListItem>
            </List>
          </Box>
        );
      case 'security':
        return (
          <Box>
            <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
              Security
            </Typography>
            <Button 
              variant="outlined" 
              sx={{ 
                color: '#008080',
                borderColor: '#008080',
                borderRadius: '9999px',
                fontWeight: 600,
                textTransform: 'none',
                '&:hover': {
                  borderColor: '#006666',
                  backgroundColor: 'rgba(0, 128, 128, 0.05)'
                }
              }}
            >
              Change Password
            </Button>
          </Box>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Typography 
          variant="h4" 
          sx={{ 
            fontWeight: 700, 
            color: '#008080',
            mb: 3,
            textAlign: 'center'
          }}
        >
          My Profile
        </Typography>

        <Card sx={{ 
          borderRadius: '16px', 
          boxShadow: '0 4px 12px rgba(0, 128, 128, 0.1)',
          overflow: 'visible'
        }}>
          <CardContent>
            <Grid container spacing={3}>
              <Grid item xs={12} md={4}>
                <Card sx={{ 
                  borderRadius: '16px', 
                  boxShadow: 'none',
                  backgroundColor: '#F4F9F9',
                  mb: 2
                }}>
                  <CardContent>
                    <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', mb: 2 }}>
                      <Avatar 
                        sx={{ 
                          width: 80, 
                          height: 80, 
                          mb: 2,
                          backgroundColor: '#008080',
                          fontSize: '2rem'
                        }}
                      >
                        {user.name.charAt(0)}
                      </Avatar>
                      <Typography variant="h6" sx={{ fontWeight: 600 }}>
                        {user.name}
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        {user.email}
                      </Typography>
                      <Chip 
                        label="Verified User" 
                        size="small" 
                        sx={{ 
                          mt: 1,
                          backgroundColor: '#E0F7F7', 
                          color: '#008080', 
                          fontWeight: 600
                        }} 
                      />
                    </Box>
                  </CardContent>
                </Card>

                <Card sx={{ 
                  borderRadius: '16px', 
                  boxShadow: 'none',
                  backgroundColor: '#F4F9F9'
                }}>
                  <CardContent>
                    <List>
                      {menuItems.map((item) => (
                        <ListItem 
                          key={item.id}
                          disablePadding
                          sx={{ mb: 0.5 }}
                        >
                          <MenuButton
                            onClick={() => setActiveTab(item.id)}
                            className={activeTab === item.id ? 'Mui-selected' : ''}
                          >
                            <ListItemIcon sx={{ minWidth: 40, color: activeTab === item.id ? '#008080' : 'inherit' }}>
                              {item.icon}
                            </ListItemIcon>
                            <ListItemText 
                              primary={item.label} 
                              primaryTypographyProps={{ 
                                sx: { 
                                  color: activeTab === item.id ? '#008080' : 'inherit',
                                  fontWeight: activeTab === item.id ? 600 : 400
                                } 
                              }} 
                            />
                          </MenuButton>
                        </ListItem>
                      ))}
                    </List>
                  </CardContent>
                </Card>
              </Grid>

              <Grid item xs={12} md={8}>
                <Card sx={{ 
                  borderRadius: '16px', 
                  boxShadow: 'none',
                  minHeight: '400px'
                }}>
                  <CardContent>
                    {renderContent()}
                  </CardContent>
                </Card>
              </Grid>
            </Grid>
          </CardContent>
        </Card>
      </Box>
    </Container>
  );
};

export default Profile;
